import { useState, useEffect } from 'react';
import { Badge } from '../components/UI';
import { DEMO_ORDERS, DEMO_RIDERS, timeAgo, apiCall } from '../utils';

function StatCard({ label, value, sub, accent, icon }) {
  return (
    <div style={{
      background:'rgba(255,255,255,.04)', border:'1px solid rgba(255,255,255,.08)',
      borderRadius:16, padding:'22px 22px 18px', position:'relative', overflow:'hidden',
    }}>
      <div style={{position:'absolute',top:0,left:0,right:0,height:3,background:accent,borderRadius:'16px 16px 0 0'}}/>
      <div style={{display:'flex',alignItems:'flex-start',justifyContent:'space-between'}}>
        <div style={{fontSize:12,fontWeight:600,color:'rgba(255,255,255,.35)',textTransform:'uppercase',letterSpacing:'.06em'}}>{label}</div>
        <span style={{fontSize:20}}>{icon}</span>
      </div>
      <div style={{fontSize:32,fontWeight:700,color:'#f1f5f9',margin:'8px 0 4px',letterSpacing:'-1px',fontFamily:'DM Mono,monospace'}}>{value}</div>
      <div style={{fontSize:12,color:'rgba(255,255,255,.35)'}}>{sub}</div>
    </div>
  );
}

export default function AdminDashboard({ token, onNavigate }) {
  const [stats, setStats] = useState(null);
  const [orders, setOrders] = useState([]);

  useEffect(() => { load(); }, []);

  async function load() {
    try {
      const data = await apiCall('/orders/dashboard/stats', token);
      if (data.success) setStats(data.stats);
      else loadDemo();
    } catch { loadDemo(); }

    try {
      const data = await apiCall('/orders?limit=10', token);
      if (data.success && data.orders?.length) setOrders(data.orders);
      else setOrders(DEMO_ORDERS);
    } catch { setOrders(DEMO_ORDERS); }
  }

  function loadDemo() {
    const totalCash = DEMO_RIDERS.reduce((s,r)=>s+(r.current_cash||0),0);
    setStats({
      today_total:47, today_delivered:32, today_pending:8, today_cancelled:3,
      active_riders: DEMO_RIDERS.filter(r=>r.status==='online').length,
      total_cash_in_hand: totalCash,
      today_failed:3, today_returned:1,
    });
  }

  const cashAlert = stats && stats.total_cash_in_hand > 50000;

  return (
    <div style={{padding:28}}>
      {/* Alert */}
      {cashAlert && (
        <div style={{display:'flex',alignItems:'center',gap:10,background:'rgba(251,191,36,.08)',border:'1px solid rgba(251,191,36,.2)',borderRadius:12,padding:'12px 18px',marginBottom:24,fontSize:13}}>
          <span style={{fontSize:18}}>⚠️</span>
          <span style={{color:'#fbbf24',fontWeight:600}}>৳{stats.total_cash_in_hand.toLocaleString()} uncollected COD</span>
          <span style={{color:'rgba(255,255,255,.5)'}}> — Riders are nearing their cash limits. Collect cash soon.</span>
          <button onClick={()=>onNavigate('finance')} style={{marginLeft:'auto',background:'rgba(251,191,36,.15)',border:'1px solid rgba(251,191,36,.3)',color:'#fbbf24',borderRadius:8,padding:'5px 14px',fontSize:12,fontWeight:600,cursor:'pointer'}}>Go to Finance →</button>
        </div>
      )}

      {/* Stats */}
      <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(165px,1fr))',gap:14,marginBottom:28}}>
        <StatCard label="Today's Orders" value={stats?.today_total ?? '—'} sub="All statuses" accent="#3b82f6" icon="📦"/>
        <StatCard label="Delivered" value={stats?.today_delivered ?? '—'} sub="Completed today" accent="#10b981" icon="✅"/>
        <StatCard label="Pending" value={stats?.today_pending ?? '—'} sub="Awaiting assignment" accent="#f59e0b" icon="⏳"/>
        <StatCard label="Failed / Cancelled" value={stats ? (stats.today_failed||0)+(stats.today_cancelled||0) : '—'} sub="Today" accent="#ef4444" icon="❌"/>
        <StatCard label="Active Riders" value={stats?.active_riders ?? '—'} sub="Currently online" accent="#a78bfa" icon="🛵"/>
        <StatCard label="Cash In Hand" value={stats ? '৳'+Number(stats.total_cash_in_hand).toLocaleString() : '—'} sub="Across all riders" accent="#f59e0b" icon="💰"/>
      </div>

      {/* Recent Orders */}
      <div style={{background:'rgba(255,255,255,.04)',border:'1px solid rgba(255,255,255,.08)',borderRadius:16,overflow:'hidden'}}>
        <div style={{display:'flex',alignItems:'center',padding:'18px 22px',borderBottom:'1px solid rgba(255,255,255,.07)'}}>
          <div>
            <div style={{fontSize:15,fontWeight:700,color:'#f1f5f9'}}>Recent Orders</div>
            <div style={{fontSize:12,color:'rgba(255,255,255,.3)',marginTop:2}}>Last 10 orders across all merchants</div>
          </div>
          <button onClick={()=>onNavigate('orders')} style={{marginLeft:'auto',background:'rgba(59,130,246,.2)',border:'1px solid rgba(59,130,246,.3)',color:'#93c5fd',borderRadius:9,padding:'7px 16px',fontSize:12,fontWeight:600,cursor:'pointer'}}>View All →</button>
        </div>
        <div style={{overflowX:'auto'}}>
          <table style={{width:'100%',borderCollapse:'collapse'}}>
            <thead>
              <tr>
                {['Tracking ID','Customer','Merchant','Zone','COD Amount','Status','Time'].map(h=>(
                  <th key={h} style={{textAlign:'left',padding:'11px 20px',fontSize:11,fontWeight:600,color:'rgba(255,255,255,.3)',textTransform:'uppercase',letterSpacing:'.06em',borderBottom:'1px solid rgba(255,255,255,.07)',background:'rgba(0,0,0,.2)'}}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {orders.map((o,i)=>(
                <tr key={i} style={{borderBottom:'1px solid rgba(255,255,255,.05)'}}
                  onMouseEnter={e=>e.currentTarget.style.background='rgba(255,255,255,.03)'}
                  onMouseLeave={e=>e.currentTarget.style.background='transparent'}
                >
                  <td style={{padding:'14px 20px'}}><span style={{fontFamily:'DM Mono,monospace',fontSize:12,color:'#60a5fa'}}>{o.tracking_id}</span></td>
                  <td style={{padding:'14px 20px'}}>
                    <div style={{fontSize:13,fontWeight:600,color:'#e2e8f0'}}>{o.customer_name}</div>
                    <div style={{fontSize:11,color:'rgba(255,255,255,.3)'}}>{o.customer_phone}</div>
                  </td>
                  <td style={{padding:'14px 20px',fontSize:13,color:'rgba(255,255,255,.6)'}}>{o.merchant_name||'—'}</td>
                  <td style={{padding:'14px 20px',fontSize:13,color:'rgba(255,255,255,.6)'}}>{o.zone_name||'—'}</td>
                  <td style={{padding:'14px 20px',fontFamily:'DM Mono,monospace',fontSize:13,fontWeight:600,color:'#fbbf24'}}>৳{Number(o.cod_amount||0).toLocaleString()}</td>
                  <td style={{padding:'14px 20px'}}><Badge status={o.status}/></td>
                  <td style={{padding:'14px 20px',fontSize:12,color:'rgba(255,255,255,.3)'}}>{timeAgo(o.created_at)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
